struct Info {
	Info() :siz(0) {};
	Info(int siz) :siz(siz) {};

	// 要维护的值
	int siz;
	void apply(const Info& v) {
		// 如何单点修改
		siz += v.siz;
	}
};
Info operator+(const Info& a, const Info& b) {
	Info c;
	c.siz = a.siz + b.siz;
	return c;
}

void solve(int CASE)
{
	int n; cin >> n;
	var a = vector<ll>(n + 1);
	var pre = vector<ll>(n + 1);
	var b = vector<ll>();
	b.pb(0);
	fa(i, 1, n)cin >> a[i], pre[i] = pre[i - 1] + a[i], b.pb(pre[i]);
	sort(all(b));
	b.erase(unique(all(b)), b.end());
	var find = [&](ll x)->ll {
		return upper_bound(all(b), x) - b.begin();
		};
	fa(i, 0, n)pre[i] = find(pre[i]);

	var cnt = vector<int>(n + 1);
	var t = FenwickTree<int>(b.size() + 10);
	fa(i, 0, n) {
		t.update(pre[i], 1);
		if (pre[i] != 1)
			cnt[i] = t.query(pre[i] - 1);
	}

	var init = vector<Info>(n + 1);
	fa(i, 1, n)init[i] = 1;
	var seg = SegmentTree<Info>(init);
	var ans = vector<int>(n + 1);
	fb(i, n, 1) {
		int k = cnt[i - 1] + 1;
		ans[i] = seg.query(k);
		seg.modify(ans[i], -1);
	}
	fa(i, 1, n)cout << ans[i] << " \n"[i == n];
	return;
}

