	var p = vector<pll>(n); 
	fa(i, 0, n - 1)p[i] = { pre[i], i + 1 };
	sort(all(p), [](pll& a, pll& b)->bool {
		if (a.px == b.px)return a.py < b.py;
		return a.px > b.px;
		});
	var ans = vector<int>(n + 1);
	fa(i, 0, n - 1)ans[p[i].py] = i + 1;
	fa(i, 1, n)cout << ans[i] << " \n"[i == n];
	return;
}
